6	} from "@openuidev/react-lang";
7	import React from "react";
8	import { genericLibrary } from "@/config/openui/genericLibrary";
9	import { dispatchOpenUIAction } from "@/features/chat/actions/openUIActionDispatcher";
10	import { normalizeOpenUICode } from "@/features/chat/utils/openUIParser";
11	import { useAppendToInput } from "@/stores/composerStore";
12	
13	interface OpenUIRendererProps {
14	  code: string;
15	  isStreaming: boolean;
16	}
17	
18	function OpenUIShimmer() {
19	  return (
20	    <div className="w-full max-w-lg animate-pulse rounded-2xl bg-zinc-800 p-4">
21	      <div className="space-y-2.5">
22	        <div className="h-3 w-full rounded-lg bg-zinc-700/70" />
23	        <div className="h-3 w-5/6 rounded-lg bg-zinc-700/70" />
24	        <div className="h-3 w-2/3 rounded-lg bg-zinc-700/70" />
25	      </div>
26	      <div className="mt-4 h-24 w-full rounded-xl bg-zinc-700/50" />
27	    </div>
28	  );
29	}
30	
31	function OpenUIErrorCard({ code, error }: { code: string; error?: string }) {
32	  return (
33	    <div className="rounded-2xl bg-zinc-800 p-4 w-full max-w-lg">
34	      <div className="flex items-center gap-2 mb-2">
35	        <Alert01Icon className="h-4 w-4 text-red-400 shrink-0" />
36	        <p className="text-sm font-medium text-red-400">
37	          Component failed to render
38	        </p>
39	      </div>
40	      {error && <p className="text-xs text-zinc-500 mb-2">{error}</p>}
41	      <pre className="rounded-xl bg-zinc-900 p-3 text-xs text-zinc-400 overflow-x-auto whitespace-pre-wrap break-all">
42	        {code}
43	      </pre>
44	    </div>
45	  );
46	}
47	
48	function OpenUIRendererInner({ code, isStreaming }: OpenUIRendererProps) {
49	  const appendToInput = useAppendToInput();
50	  const normalizedCode = React.useMemo(
51	    () => normalizeOpenUICode(code, genericLibrary),
52	    [code],
53	  );
54	
55	  const [failedForCode, setFailedForCode] = React.useState<string | null>(null);
56	  const [failureReason, setFailureReason] = React.useState<string>("");
57	  const [hasRendered, setHasRendered] = React.useState(false);
58	  const parseFailed = !isStreaming && failedForCode === normalizedCode;
59	
60	  const handleAction = React.useCallback(
61	    (event: ActionEvent) => {
62	      dispatchOpenUIAction(event, appendToInput).catch((err) => {
63	        console.error("[OpenUIRenderer] Action dispatch failed:", err);
64	      });
65	    },
66	    [appendToInput],
67	  );
68	
69	  const handleParseResult = React.useCallback(
70	    (result: ParseResult | null) => {
71	      if (!result) return;
72	      if (result.root !== null && !hasRendered) {
73	        setHasRendered(true);
74	      }
75	      const failed = result.root === null && !isStreaming;
76	      if (failed) {
77	        const errors = result.meta?.validationErrors;
78	        const reason = errors?.length
79	          ? errors
80	              .map((e: unknown) =>
81	                typeof e === "string" ? e : JSON.stringify(e),
82	              )
83	              .join("; ")
84	          : "Parse produced no root node";
85	        console.error(`[OpenUIRenderer] ${reason}`, {
86	          rawCode: code,
87	          normalizedCode,
88	          unresolved: result.meta?.unresolved,
89	          statementCount: result.meta?.statementCount,
90	        });
91	        setFailedForCode(normalizedCode);
92	        setFailureReason(reason);
93	      } else {
94	        setFailedForCode(null);
95	        setFailureReason("");
96	      }
97	    },
98	    [code, normalizedCode, isStreaming, hasRendered],
99	  );
100	
101	  if (parseFailed) {
102	    return <OpenUIErrorCard code={code} error={failureReason} />;
103	  }
104	
105	  const showShimmer = isStreaming && !hasRendered;
106	
107	  return (
108	    <>
109	      {showShimmer && <OpenUIShimmer />}
110	      <div className={showShimmer ? "hidden" : undefined}>
111	        <Renderer
112	          response={normalizedCode}
113	          library={genericLibrary}
114	          isStreaming={isStreaming}
115	          onAction={handleAction}
116	          onParseResult={handleParseResult}
117	        />
118	      </div>
119	    </>
120	  );
121	}
122	
123	class OpenUIErrorBoundary extends React.Component<
124	  { children: React.ReactNode; code: string },
125	  { hasError: boolean; errorMessage: string }
126	> {
127	  constructor(props: { children: React.ReactNode; code: string }) {
128	    super(props);
129	    this.state = { hasError: false, errorMessage: "" };
130	  }
131	
132	  static getDerivedStateFromError(error: Error) {
133	    return { hasError: true, errorMessage: error.message };
134	  }
135	
136	  componentDidUpdate(prevProps: { code: string }) {
137	    if (this.state.hasError && prevProps.code !== this.props.code) {
138	      this.setState({ hasError: false, errorMessage: "" });
139	    }
140	  }
141	
142	  componentDidCatch(error: Error, info: React.ErrorInfo) {
143	    console.error("[OpenUIRenderer] Render error:", error, info, {
144	      code: this.props.code,
145	    });
146	  }
147	
148	  render() {
149	    if (this.state.hasError) {
150	      return (
151	        <OpenUIErrorCard
152	          code={this.props.code}
153	          error={this.state.errorMessage}
154	        />
155	      );
156	    }
157	    return this.props.children;
158	  }
159	}
160	
161	export default function OpenUIRenderer({
162	  code,
163	  isStreaming,
164	}: OpenUIRendererProps) {
165	  return (
166	    <OpenUIErrorBoundary code={code}>
167	      <div className="my-4">
168	        <OpenUIRendererInner code={code} isStreaming={isStreaming} />
169	      </div>
170	    </OpenUIErrorBoundary>
171	  );
172	}
