26	    </div>
27	  );
28	}
29	
30	function OpenUIErrorCard({ code, error }: { code: string; error?: string }) {
31	  return (
32	    <div className="rounded-2xl bg-zinc-800 p-4 w-full max-w-lg">
33	      <div className="flex items-center gap-2 mb-2">
34	        <Alert01Icon className="h-4 w-4 text-red-400 shrink-0" />
35	        <p className="text-sm font-medium text-red-400">
36	          Component failed to render
37	        </p>
38	      </div>
39	      {error && <p className="text-xs text-zinc-500 mb-2">{error}</p>}
40	      <pre className="rounded-xl bg-zinc-900 p-3 text-xs text-zinc-400 overflow-x-auto whitespace-pre-wrap break-all">
41	        {code}
42	      </pre>
43	    </div>
44	  );
45	}
46	
47	function OpenUIRendererInner({ code, isStreaming }: OpenUIRendererProps) {
48	  const appendToInput = useAppendToInput();
49	  const normalizedCode = React.useMemo(
50	    () => normalizeOpenUICode(code, genericLibrary),
51	    [code],
52	  );
53	
54	  const [failedForCode, setFailedForCode] = React.useState<string | null>(null);
55	  const [failureReason, setFailureReason] = React.useState<string>("");
56	  const [hasRendered, setHasRendered] = React.useState(false);
57	  const parseFailed = !isStreaming && failedForCode === normalizedCode;
58	
59	  const handleAction = React.useCallback(
60	    (event: ActionEvent) => {
61	      dispatchOpenUIAction(event, {
62	        appendToInput,
63	        openUrl: (url) => {
64	          window.open(url, "_blank", "noopener,noreferrer");
65	        },
66	      }).catch((err) => {
67	        console.error("[OpenUIRenderer] Action dispatch failed:", err);
68	      });
69	    },
70	    [appendToInput],
71	  );
72	
73	  const handleParseResult = React.useCallback(
74	    (result: ParseResult | null) => {
75	      if (!result) return;
76	      if (result.root !== null && !hasRendered) {
77	        setHasRendered(true);
78	      }
79	      const failed = result.root === null && !isStreaming;
80	      if (failed) {
81	        const errors = result.meta?.validationErrors;
82	        const reason = errors?.length
83	          ? errors
84	              .map((e: unknown) =>
85	                typeof e === "string" ? e : JSON.stringify(e),
86	              )
87	              .join("; ")
88	          : "Parse produced no root node";
89	        console.error(`[OpenUIRenderer] ${reason}`, {
90	          rawCode: code,
91	          normalizedCode,
92	          unresolved: result.meta?.unresolved,
93	          statementCount: result.meta?.statementCount,
94	        });
95	        setFailedForCode(normalizedCode);
96	        setFailureReason(reason);
97	      } else {
98	        setFailedForCode(null);
99	        setFailureReason("");
100	      }
101	    },
102	    [code, normalizedCode, isStreaming, hasRendered],
103	  );
104	
105	  if (parseFailed) {
106	    return <OpenUIErrorCard code={code} error={failureReason} />;
107	  }
108	
109	  const showShimmer = isStreaming && !hasRendered;
110	
111	  return (
112	    <>
113	      {showShimmer && <OpenUIShimmer />}
114	      <div className={showShimmer ? "hidden" : undefined}>
115	        <Renderer
116	          response={normalizedCode}
117	          library={genericLibrary}
118	          isStreaming={isStreaming}
119	          onAction={handleAction}
120	          onParseResult={handleParseResult}
121	        />
122	      </div>
123	    </>
124	  );
125	}
126	
127	class OpenUIErrorBoundary extends React.Component<
128	  { children: React.ReactNode; code: string },
129	  { hasError: boolean; errorMessage: string }
130	> {
131	  constructor(props: { children: React.ReactNode; code: string }) {
132	    super(props);
133	    this.state = { hasError: false, errorMessage: "" };
134	  }
135	
136	  static getDerivedStateFromError(error: Error) {
137	    return { hasError: true, errorMessage: error.message };
138	  }
139	
140	  componentDidUpdate(prevProps: { code: string }) {
141	    if (this.state.hasError && prevProps.code !== this.props.code) {
142	      this.setState({ hasError: false, errorMessage: "" });
143	    }
144	  }
145	
146	  componentDidCatch(error: Error, info: React.ErrorInfo) {
147	    console.error("[OpenUIRenderer] Render error:", error, info, {
148	      code: this.props.code,
149	    });
150	  }
151	
152	  render() {
153	    if (this.state.hasError) {
154	      return (
155	        <OpenUIErrorCard
156	          code={this.props.code}
157	          error={this.state.errorMessage}
158	        />
159	      );
160	    }
161	    return this.props.children;
162	  }
163	}
164	
165	export default function OpenUIRenderer({
166	  code,
167	  isStreaming,
168	}: OpenUIRendererProps) {
169	  return (
170	    <OpenUIErrorBoundary code={code}>
171	      <div className="my-4">
